c
// CORRECT pattern for job table access:
void modify_job_table(void) {
SignalBlockContext ctx;
// Block SIGCHLD - handler will NOT interrupt
if (signal_block_sigchld(&ctx) < 0) {
return;  // Error handling
}
// === CRITICAL SECTION ===
// Safe to modify g_job_control.job_list
job->next = job_list;
job_list = job;
// ========================
// Unblock - pending SIGCHLD now delivered
signal_unblock_sigchld(&ctx);
}
// WRONG - Race condition!
void wrong_pattern(void) {
job->next = job_list;     // SIGCHLD could interrupt here!
job_list = job;           // Handler reads inconsistent state
}
